sw_js = "// Droidify Service Worker\n// Network-only — no caching. Exists for PWA installability + Background Sync.\n\nconst SYNC_TAG = 'droidify-search-sync';\n\nself.addEventListener('install', () => self.skipWaiting());\n\nself.addEventListener('activate', e => e.waitUntil(\n  caches.keys()\n    .then(keys => Promise.all(keys.map(k => caches.delete(k))))\n    .then(() => self.clients.claim())\n));\n\n// Passthrough — skip navigation requests entirely (fixes Safari localhost error)\nself.addEventListener('fetch', event => {\n  const url = event.request.url;\n  if (!url.startsWith('http')) return;\n  if (event.request.mode === 'navigate') return;\n  if (event.request.method !== 'GET') return;\n  if (!url.startsWith(self.registration.scope)) return;\n  event.respondWith(fetch(event.request).catch(() => new Response('', { status: 503 })));\n});\n\nself.addEventListener('sync', event => {\n  if (event.tag === SYNC_TAG) {\n    event.waitUntil(\n      self.clients.matchAll({ type: 'window' })\n        .then(clients => clients.forEach(c => c.postMessage({ type: 'SYNC_COMPLETE' })))\n    );\n  }\n});\n\nself.addEventListener('periodicsync', event => {\n  if (event.tag === 'droidify-refresh') {\n    event.waitUntil(\n      Promise.all([\n        fetch('/api/devices?limit=1').catch(() => {}),\n        fetch('/api/roms?limit=1').catch(() => {}),\n      ])\n    );\n  }\n});\n\nself.addEventListener('message', event => {\n  if (event.data && event.data.type === 'SKIP_WAITING') self.skipWaiting();\n});\n"

